blocks.body:
{
    "level": "A2–B1",
    "intro": "W tym temacie nauczysz się tworzyć <strong>pytania alternatywne</strong>, czyli pytania oferujące wybór między kilkoma opcjami.",
    "rules": [
        {
            "label": "DWIE OPCJE",
            "color": "emerald",
            "text": "Najczęściej pytamy o <strong>wybór między dwiema możliwościami</strong>:",
            "example": "Do you prefer coffee or tea?"
        },
        {
            "label": "STRUKTURA",
            "color": "blue",
            "text": "Budujemy je jak pytanie ogólne, a potem dodajemy <strong>or + druga opcja</strong>:",
            "example": "Is it black or white?"
        },
        {
            "label": "ODPOWIEDŹ",
            "color": "amber",
            "text": "Najczęściej wybieramy jedną z opcji zamiast odpowiadać tylko yes/no:",
            "example": "Tea, please. / I'd prefer coffee."
        }
    ]
}

{
    "title": "1. Czym są pytania alternatywne?",
    "intro": "Pytanie alternatywne prowadzi rozmówcę do wyboru jednej z opcji:",
    "items": [
        {
            "label": "Pytanie tak/nie",
            "title": "Do you like coffee?",
            "subtitle": "Odpowiedź: yes / no"
        },
        {
            "label": "Pytanie alternatywne",
            "title": "Do you like coffee or tea?",
            "subtitle": "Odpowiedź: coffee / tea"
        },
        {
            "label": "Struktura",
            "title": "Question + or + alternative",
            "subtitle": "Najpierw pytanie, potem wybór między opcjami"
        }
    ]
}

{
    "title": "2. Podstawowa struktura",
    "sections": [
        {
            "label": "Z rzeczownikami",
            "color": "emerald",
            "description": "Najprostsza forma to wybór między dwoma rzeczownikami lub grupami rzeczownikowymi.",
            "examples": [
                {
                    "en": "Do you prefer coffee or tea?",
                    "ua": "Wolisz kawę czy herbatę?"
                },
                {
                    "en": "Would you like meat or fish?",
                    "ua": "Wolisz mięso czy rybę?"
                },
                {
                    "en": "Is she a teacher or a doctor?",
                    "ua": "Czy ona jest nauczycielką czy lekarką?"
                },
                {
                    "en": "Are you from Spain or Italy?",
                    "ua": "Jesteś z Hiszpanii czy z Włoch?"
                }
            ]
        },
        {
            "label": "Z przymiotnikami",
            "color": "sky",
            "description": "Pytanie alternatywne może też dotyczyć opisu lub cechy.",
            "examples": [
                {
                    "en": "Is it big or small?",
                    "ua": "Czy to jest duże czy małe?"
                },
                {
                    "en": "Was the test easy or difficult?",
                    "ua": "Czy test był łatwy czy trudny?"
                },
                {
                    "en": "Are you happy or sad?",
                    "ua": "Jesteś szczęśliwy czy smutny?"
                },
                {
                    "en": "Was the film good or bad?",
                    "ua": "Film był dobry czy słaby?"
                }
            ]
        },
        {
            "label": "Struktura",
            "color": "purple",
            "description": "Ogólna formuła pytania alternatywnego wygląda tak:",
            "examples": [
                {
                    "en": "Auxiliary + subject + verb + option A + or + option B?",
                    "ua": "Czasownik pomocniczy + podmiot + czasownik + opcja A + or + opcja B?"
                }
            ],
            "note": "📌 Pytanie alternatywne zachowuje strukturę pytania ogólnego, ale dodaje wybór między opcjami."
        }
    ]
}

{
    "title": "3. Pytania alternatywne z DO/DOES/DID",
    "sections": [
        {
            "label": "Present Simple",
            "color": "emerald",
            "description": "W Present Simple używamy <strong>do</strong> albo <strong>does</strong>.",
            "examples": [
                {
                    "en": "Do you walk or drive to work?",
                    "ua": "Do pracy chodzisz pieszo czy jedziesz samochodem?"
                },
                {
                    "en": "Does she like cats or dogs?",
                    "ua": "Czy ona lubi koty czy psy?"
                },
                {
                    "en": "Do they live in a house or a flat?",
                    "ua": "Czy mieszkają w domu czy w mieszkaniu?"
                }
            ]
        },
        {
            "label": "Past Simple",
            "color": "sky",
            "description": "W Past Simple używamy <strong>did</strong>.",
            "examples": [
                {
                    "en": "Did you go by bus or by train?",
                    "ua": "Pojechałeś autobusem czy pociągiem?"
                },
                {
                    "en": "Did she buy a laptop or a tablet?",
                    "ua": "Kupiła laptop czy tablet?"
                },
                {
                    "en": "Did they win or lose?",
                    "ua": "Wygrali czy przegrali?"
                }
            ]
        },
        {
            "label": "Różne czasowniki i części zdania",
            "color": "amber",
            "description": "Alternatywa może łączyć nie tylko rzeczowniki, ale też czasowniki i inne elementy zdania.",
            "examples": [
                {
                    "en": "Do you want to stay or leave?",
                    "ua": "Chcesz zostać czy wyjść?"
                },
                {
                    "en": "Did you call him or text him?",
                    "ua": "Dzwoniłeś do niego czy napisałeś wiadomość?"
                },
                {
                    "en": "Does he work or study?",
                    "ua": "On pracuje czy studiuje?"
                }
            ],
            "note": "📌 <strong>Or</strong> może łączyć czasowniki, rzeczowniki, przymiotniki i całe frazy."
        }
    ]
}

{
    "title": "4. Pytania alternatywne z TO BE",
    "sections": [
        {
            "label": "Present Simple",
            "color": "blue",
            "description": "Z <strong>to be</strong> po prostu ustawiamy formę czasownika przed podmiotem.",
            "examples": [
                {
                    "en": "Are you a student or a teacher?",
                    "ua": "Jesteś studentem czy nauczycielem?"
                },
                {
                    "en": "Is it hot or cold outside?",
                    "ua": "Na dworze jest gorąco czy zimno?"
                },
                {
                    "en": "Are they British or American?",
                    "ua": "Są Brytyjczykami czy Amerykanami?"
                }
            ]
        },
        {
            "label": "Past Simple",
            "color": "purple",
            "description": "W czasie przeszłym używamy <strong>was</strong> albo <strong>were</strong>.",
            "examples": [
                {
                    "en": "Was the book interesting or boring?",
                    "ua": "Książka była ciekawa czy nudna?"
                },
                {
                    "en": "Were you at home or at work?",
                    "ua": "Byłeś w domu czy w pracy?"
                },
                {
                    "en": "Was she happy or upset?",
                    "ua": "Była szczęśliwa czy zdenerwowana?"
                }
            ]
        },
        {
            "label": "Identyfikowanie obiektów",
            "color": "rose",
            "description": "Pytania alternatywne z <strong>to be</strong> są częste przy rozpoznawaniu i nazywaniu rzeczy.",
            "examples": [
                {
                    "en": "Is this your bag or hers?",
                    "ua": "To jest twoja torba czy jej?"
                },
                {
                    "en": "Is it a cat or a dog?",
                    "ua": "To kot czy pies?"
                },
                {
                    "en": "Are these apples or pears?",
                    "ua": "To jabłka czy gruszki?"
                }
            ],
            "note": "📌 Najczęściej wybieramy jedną z podanych możliwości, a nie odpowiadamy samym <em>yes</em> albo <em>no</em>."
        }
    ]
}

{
    "title": "5. Pytania alternatywne z modalnymi",
    "sections": [
        {
            "label": "CAN / COULD",
            "color": "emerald",
            "description": "Z <strong>can</strong> i <strong>could</strong> pytamy o możliwość albo umiejętność.",
            "examples": [
                {
                    "en": "Can you swim or dive?",
                    "ua": "Umiesz pływać czy nurkować?"
                },
                {
                    "en": "Could we meet today or tomorrow?",
                    "ua": "Moglibyśmy się spotkać dziś czy jutro?"
                },
                {
                    "en": "Can she speak French or German?",
                    "ua": "Ona mówi po francusku czy po niemiecku?"
                }
            ]
        },
        {
            "label": "WILL / WOULD",
            "color": "sky",
            "description": "Z <strong>will</strong> i <strong>would</strong> mówimy o przyszłości, planach i preferencjach.",
            "examples": [
                {
                    "en": "Will you come by car or by bus?",
                    "ua": "Przyjedziesz samochodem czy autobusem?"
                },
                {
                    "en": "Would you like wine or beer?",
                    "ua": "Wolałbyś wino czy piwo?"
                },
                {
                    "en": "Will they arrive in the morning or in the evening?",
                    "ua": "Przyjadą rano czy wieczorem?"
                }
            ]
        },
        {
            "label": "SHOULD / MUST",
            "color": "amber",
            "description": "Pytania alternatywne z modalami bywają też przydatne przy radach i obowiązkach.",
            "examples": [
                {
                    "en": "Should I call or text you?",
                    "ua": "Mam do ciebie zadzwonić czy napisać?"
                },
                {
                    "en": "Must we pay cash or by card?",
                    "ua": "Musimy zapłacić gotówką czy kartą?"
                }
            ],
            "note": "📌 Struktura: <strong>modal + subject + verb + option A + or + option B</strong>."
        }
    ]
}

{
    "title": "6. Bardziej złożone pytania alternatywne",
    "sections": [
        {
            "label": "Z frazami i całymi zdaniami",
            "color": "purple",
            "description": "Alternatywa może łączyć całe frazy, a nawet całe części zdania.",
            "examples": [
                {
                    "en": "Do you want to go now or wait a little?",
                    "ua": "Chcesz iść teraz czy trochę poczekać?"
                },
                {
                    "en": "Shall we eat at home or go to a restaurant?",
                    "ua": "Zjemy w domu czy pójdziemy do restauracji?"
                },
                {
                    "en": "Will you study English or another language?",
                    "ua": "Będziesz się uczyć angielskiego czy innego języka?"
                }
            ]
        },
        {
            "label": "Więcej niż dwie opcje",
            "color": "blue",
            "description": "Możesz zaproponować także trzy albo więcej wariantów.",
            "examples": [
                {
                    "en": "Do you prefer red, blue or green?",
                    "ua": "Wolisz czerwony, niebieski czy zielony?"
                },
                {
                    "en": "Should we meet on Monday, Tuesday or Wednesday?",
                    "ua": "Spotkamy się w poniedziałek, wtorek czy środę?"
                },
                {
                    "en": "Is she from France, Spain or Italy?",
                    "ua": "Jest z Francji, Hiszpanii czy z Włoch?"
                }
            ]
        },
        {
            "label": "Ze słowami Wh",
            "color": "rose",
            "description": "Pytanie alternatywne może też zaczynać się od słowa pytającego.",
            "examples": [
                {
                    "en": "Which do you prefer — coffee or tea?",
                    "ua": "Co wolisz — kawę czy herbatę?"
                },
                {
                    "en": "Where should we go — to the park or to the beach?",
                    "ua": "Gdzie powinniśmy pójść — do parku czy na plażę?"
                },
                {
                    "en": "When will you come — today or tomorrow?",
                    "ua": "Kiedy przyjedziesz — dziś czy jutro?"
                }
            ],
            "note": "📌 W pytaniach tego typu szczególnie często pojawia się <strong>which</strong>."
        }
    ]
}

{
    "title": "7. Jak odpowiadać",
    "sections": [
        {
            "label": "Wybierz jedną opcję",
            "color": "emerald",
            "description": "Najczęściej odpowiadamy, wybierając jedną z zaproponowanych możliwości.",
            "examples": [
                {
                    "en": "Q: Coffee or tea? — A: Tea, please.",
                    "ua": "Kawa czy herbata? — Herbatę, proszę."
                },
                {
                    "en": "Q: Is it black or white? — A: It's black.",
                    "ua": "To jest czarne czy białe? — Jest czarne."
                },
                {
                    "en": "Q: Do you walk or drive? — A: I usually drive.",
                    "ua": "Chodzisz pieszo czy jedziesz? — Zwykle jadę samochodem."
                }
            ]
        },
        {
            "label": "Odrzuć obie opcje",
            "color": "sky",
            "description": "Możesz też odrzucić obie propozycje i podać trzecią możliwość.",
            "examples": [
                {
                    "en": "Q: Coffee or tea? — A: Neither. I'll have water.",
                    "ua": "Kawa czy herbata? — Żadna z nich. Poproszę wodę."
                },
                {
                    "en": "Q: Are you from Spain or Italy? — A: Neither. I'm from France.",
                    "ua": "Jesteś z Hiszpanii czy z Włoch? — Z żadnego z tych krajów. Jestem z Francji."
                }
            ]
        },
        {
            "label": "Wybierz obie opcje",
            "color": "amber",
            "description": "Czasem można też zaakceptować oba warianty.",
            "examples": [
                {
                    "en": "Q: Do you like cats or dogs? — A: Both!",
                    "ua": "Lubisz koty czy psy? — Oba!"
                },
                {
                    "en": "Q: Coffee or tea? — A: I like both.",
                    "ua": "Kawa czy herbata? — Lubię jedno i drugie."
                }
            ],
            "note": "📌 <strong>Neither</strong> = żadne, <strong>both</strong> = oba."
        }
    ]
}

{
    "title": "8. Pytanie ogólne vs pytanie alternatywne",
    "intro": "Najważniejsze różnice między tymi dwoma typami pytań:",
    "rows": [
        {
            "en": "Yes / No Question",
            "ua": "Pytanie ogólne",
            "note": "Do you like coffee? → yes / no"
        },
        {
            "en": "Alternative Question",
            "ua": "Pytanie alternatywne",
            "note": "Do you like coffee or tea? → coffee / tea"
        },
        {
            "en": "Structure",
            "ua": "Struktura",
            "note": "Pytanie + or + alternatywa"
        },
        {
            "en": "Answer type",
            "ua": "Typ odpowiedzi",
            "note": "Najczęściej wybór jednej z opcji"
        },
        {
            "en": "Intonation",
            "ua": "Intonacja",
            "note": "Najsilniejszy akcent zwykle pada na ostatnią opcję"
        }
    ],
    "warning": "📌 Kluczowy element pytania alternatywnego to <strong>or + wybór</strong>."
}

{
    "title": "9. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Odpowiedź yes/no zamiast wybrania opcji.",
            "wrong": "❌ Coffee or tea? — Yes.",
            "right": "✅ <span class=\"font-mono\">Coffee or tea? — Tea, please.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Zła kolejność słów w pytaniu.",
            "wrong": "❌ You prefer coffee or tea?",
            "right": "✅ <span class=\"font-mono\">Do you prefer coffee or tea?</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Brak <strong>or</strong> między opcjami.",
            "wrong": "❌ Do you want coffee tea?",
            "right": "✅ <span class=\"font-mono\">Do you want coffee or tea?</span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Niepoprawna forma czasownika po czasowniku pomocniczym.",
            "wrong": "❌ Does she likes cats or dogs?",
            "right": "✅ <span class=\"font-mono\">Does she like cats or dogs?</span>"
        }
    ]
}

{
    "title": "11. Ćwicz",
    "select_title": "Ćwiczenie 1. Wybierz właściwą opcję",
    "select_intro": "Wybierz poprawną formę pytania alternatywnego.",
    "selects": [
        {
            "label": "a) Do you prefer coffee or tea? / b) You prefer coffee or tea? / c) Do you prefer coffee and tea?",
            "prompt": "Która opcja jest poprawna?"
        },
        {
            "label": "a) Is it hot or cold? / b) It is hot or cold? / c) Does it hot or cold?",
            "prompt": "Która opcja jest poprawna?"
        },
        {
            "label": "a) Can you swim or dive? / b) Do you can swim or dive? / c) Can you swim and dive?",
            "prompt": "Która opcja jest poprawna?"
        }
    ],
    "options": [
        "a",
        "b",
        "c"
    ],
    "input_title": "Ćwiczenie 2. Ułóż pytanie alternatywne",
    "input_intro": "Utwórz pytanie z podanych opcji.",
    "inputs": [
        {
            "before": "She likes (cats / dogs). → ",
            "after": ""
        },
        {
            "before": "You are from (Spain / Italy). → ",
            "after": ""
        },
        {
            "before": "They will arrive (today / tomorrow). → ",
            "after": ""
        },
        {
            "before": "It is (big / small). → ",
            "after": ""
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błąd",
    "rephrase_intro": "Znajdź i popraw błąd w pytaniu alternatywnym.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "You prefer coffee or tea?",
            "example_target": "Do you prefer coffee or tea?"
        },
        {
            "original": "1. Does she likes cats or dogs?",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "2. Is it hot and cold?",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "3. Coffee or tea? — Yes.",
            "placeholder": "Popraw odpowiedź"
        }
    ]
}

{
    "title": "Inne lekcje w tej sekcji",
    "items": [
        {
            "label": "Formy pytań",
            "current": false
        },
        {
            "label": "Pytania typu yes / no",
            "current": false
        },
        {
            "label": "Pytania szczegółowe (wh-)",
            "current": false
        },
        {
            "label": "Odpowiedzi na pytania",
            "current": false
        },
        {
            "label": "Pytania alternatywne",
            "current": true
        },
        {
            "label": "Pytania rozłączne (question tags)",
            "current": false
        },
        {
            "label": "Pytania przeczące",
            "current": false
        }
    ]
}
